+public class SystemImageReader {
+    private static final ImageReader SYSTEM_IMAGE_READER;
+
+    static {
+        String javaHome = System.getProperty("java.home");
+        FileSystem fs;
+        if (SystemImageReader.class.getClassLoader() == null) {
